//! verify-rknot — round-trip diagnostic for Resonance Knot files
//!
//! Usage:
//!   verify-rknot --rknot <path.rknot> --dense <path.knot> \
//!     [--max-layers 5]
//!
//! For each layer:
//!   1. Load dense Q/K/V/FFN from the original `.knot`.
//!   2. Pull the matching `ResonanceKnotLayer` (manifest + four blocks)
//!      from the `.rknot`.
//!   3. Decode every block back to its dense shape (`decode_ffn_block`
//!      handles square Q on Llama and rectangular Q/K/V/FFN on Gemma4).
//!   4. Compute per-block metrics restricted to standing × standing:
//!      max abs err, mean abs err, energy ratio.
//!   5. Print a per-layer table; warn when the energy ratio falls below
//!      0.95. By default the process exits with code 1 if any block is
//!      below that line; pass `--allow-energy-warnings` for measurement-only
//!      CI (spectral compression is expected to violate the line sometimes).
//!
//! See `RKNOT_PHASE2_CONTRACTS.md` Module 5 for the contract this
//! binary satisfies. This is the bit-comparison sibling of the Phase 4
//! "Paris" inference probe — it can flag obvious encoding bugs without
//! actually running the model.

use std::path::PathBuf;
use std::process::ExitCode;

use distributed_inference::rknot::decoder::decode_ffn_block;
use distributed_inference::rknot::dense_reader::{DenseKnotReader, LayerTensors};
use distributed_inference::rknot::format::{DenseTensor, ResonanceKnotLayer, SpectralManifest};
use distributed_inference::rknot::reader::read_rknot_from_file;

// ──────────────────────────────────────────────────────────────────────
// CLI
// ──────────────────────────────────────────────────────────────────────

#[derive(Debug, Default)]
struct Args {
    rknot: Option<PathBuf>,
    dense: Option<PathBuf>,
    max_layers: Option<u32>,
    allow_energy_warnings: bool,
    metric_scope: MetricScope,
}

#[derive(Debug, Clone, Copy, Default)]
enum MetricScope {
    #[default]
    Standing,
    Full,
}

fn print_usage() {
    eprintln!(
        "verify-rknot — round-trip diagnostic for Resonance Knot files

USAGE:
  verify-rknot --rknot <path.rknot> --dense <path.knot> [--max-layers N] \
    [--scope standing|full] [--allow-energy-warnings]

FLAGS:
  --rknot <path>       Path to the resonance knot under test (required)
  --dense <path>       Path to the original dense .knot          (required)
  --max-layers <u32>   Cap layers verified (default: all)
  --scope <mode>       Metric scope: standing (default) or full
  --allow-energy-warnings  Exit 0 even when energy_ratio < 0.95 on some blocks
                       (still exits 1 on I/O or layer load errors)
  -h, --help           Print this message"
    );
}

fn parse_args() -> Result<Args, String> {
    let mut args = Args::default();
    let mut iter = std::env::args().skip(1);
    while let Some(flag) = iter.next() {
        match flag.as_str() {
            "--rknot" => {
                let v = iter
                    .next()
                    .ok_or_else(|| "--rknot requires a path".to_string())?;
                args.rknot = Some(PathBuf::from(v));
            }
            "--dense" => {
                let v = iter
                    .next()
                    .ok_or_else(|| "--dense requires a path".to_string())?;
                args.dense = Some(PathBuf::from(v));
            }
            "--max-layers" => {
                let v = iter
                    .next()
                    .ok_or_else(|| "--max-layers requires a value".to_string())?;
                args.max_layers = Some(v.parse().map_err(|e| format!("--max-layers: {e}"))?);
            }
            "--allow-energy-warnings" => {
                args.allow_energy_warnings = true;
            }
            "--scope" => {
                let v = iter
                    .next()
                    .ok_or_else(|| "--scope requires standing|full".to_string())?;
                args.metric_scope = match v.as_str() {
                    "standing" => MetricScope::Standing,
                    "full" => MetricScope::Full,
                    _ => return Err(format!("--scope must be standing|full, got {v}")),
                };
            }
            "-h" | "--help" => {
                print_usage();
                std::process::exit(0);
            }
            other => return Err(format!("unknown argument: {other}")),
        }
    }
    if args.rknot.is_none() {
        return Err("--rknot <path> is required".to_string());
    }
    if args.dense.is_none() {
        return Err("--dense <path> is required".to_string());
    }
    Ok(args)
}

// ──────────────────────────────────────────────────────────────────────
// Metrics
// ──────────────────────────────────────────────────────────────────────

/// Energy-ratio threshold below which a layer's block is considered
/// suspicious. Matches the Module 5 contract.
const ENERGY_WARN_THRESHOLD: f32 = 0.95;

#[derive(Debug, Clone, Copy)]
struct BlockMetrics {
    max_abs_err: f32,
    mean_abs_err: f32,
    /// `sum |decoded|² / sum |dense|²` restricted to standing × standing.
    /// Returns `1.0` for zero-energy dense tensors (vacuous: nothing to
    /// preserve, nothing to lose).
    energy_ratio: f32,
}

/// Restrict `(i, j)` to `standing × standing` AND inside the actual
/// `(rows, cols)` of the tensor. For Q/K/V (d × d) this is the natural
/// standing-projection slice. For FFN (d × h) this samples a sparse
/// cross-section — wherever a standing column index also falls inside
/// `[0, h)` — which is what the contract specifies as the canonical
/// energy check.
fn compute_metrics(
    dense: &DenseTensor,
    decoded: &DenseTensor,
    manifest: &SpectralManifest,
    scope: MetricScope,
) -> BlockMetrics {
    let mut max_abs_err = 0.0_f32;
    let mut sum_abs_err = 0.0_f64;
    let mut sum_decoded_sq = 0.0_f64;
    let mut sum_dense_sq = 0.0_f64;
    let mut count: u64 = 0;

    let dense_rows = dense.rows;
    let dense_cols = dense.cols;
    let decoded_rows = decoded.rows;
    let decoded_cols = decoded.cols;

    let mut sample = |i: u32, j: u32| {
        let d = dense.get(i, j);
        let r = decoded.get(i, j);
        let err = (d - r).abs();
        if err > max_abs_err {
            max_abs_err = err;
        }
        sum_abs_err += err as f64;
        sum_dense_sq += (d as f64) * (d as f64);
        sum_decoded_sq += (r as f64) * (r as f64);
        count += 1;
    };

    match scope {
        MetricScope::Standing => {
            for &i in &manifest.standing_indices {
                // Only sample positions inside both tensors; DenseTensor::get
                // would clamp to 0.0 otherwise and silently inflate "matches"
                // for out-of-range standing indices.
                if i >= dense_rows || i >= decoded_rows {
                    continue;
                }
                for &j in &manifest.standing_indices {
                    if j >= dense_cols || j >= decoded_cols {
                        continue;
                    }
                    sample(i, j);
                }
            }
        }
        MetricScope::Full => {
            let rows = dense_rows.min(decoded_rows);
            let cols = dense_cols.min(decoded_cols);
            for i in 0..rows {
                for j in 0..cols {
                    sample(i, j);
                }
            }
        }
    }

    let mean_abs_err = if count == 0 {
        0.0
    } else {
        (sum_abs_err / count as f64) as f32
    };
    let energy_ratio = if sum_dense_sq <= 0.0 {
        // No energy in the original block at standing positions.
        // Vacuously preserved: nothing to lose, nothing to gain.
        1.0
    } else {
        (sum_decoded_sq / sum_dense_sq) as f32
    };

    BlockMetrics {
        max_abs_err,
        mean_abs_err,
        energy_ratio,
    }
}

// ──────────────────────────────────────────────────────────────────────
// Per-layer pipeline
// ──────────────────────────────────────────────────────────────────────

fn warn_marker(energy_ratio: f32) -> &'static str {
    if energy_ratio < ENERGY_WARN_THRESHOLD {
        "WARN "
    } else {
        "     "
    }
}

fn print_block_row(layer_idx: u32, label: &str, metrics: &BlockMetrics, warn_count: &mut u32) {
    let marker = warn_marker(metrics.energy_ratio);
    if metrics.energy_ratio < ENERGY_WARN_THRESHOLD {
        *warn_count += 1;
    }
    println!(
        "{marker}L{:>3} {:>3}: max_err={:.4e} mean_err={:.4e} energy={:.4}",
        layer_idx, label, metrics.max_abs_err, metrics.mean_abs_err, metrics.energy_ratio,
    );
}

fn verify_layer(
    layer: &ResonanceKnotLayer,
    dense_blocks: &LayerTensors,
    warn_count: &mut u32,
    scope: MetricScope,
) {
    let manifest = &layer.manifest;
    let h = layer.ffn_block.cols;

    // Q — rectangular on Gemma4 (q_dim != hidden), square on Llama.
    let decoded_q = decode_ffn_block(&layer.q_block, manifest, layer.q_block.cols);
    let metrics_q = compute_metrics(&dense_blocks.q, &decoded_q, manifest, scope);
    print_block_row(layer.layer_idx, "Q", &metrics_q, warn_count);

    // K
    let decoded_k = decode_ffn_block(&layer.k_block, manifest, layer.k_block.cols);
    let metrics_k = compute_metrics(&dense_blocks.k, &decoded_k, manifest, scope);
    print_block_row(layer.layer_idx, "K", &metrics_k, warn_count);

    // V
    let decoded_v = decode_ffn_block(&layer.v_block, manifest, layer.v_block.cols);
    let metrics_v = compute_metrics(&dense_blocks.v, &decoded_v, manifest, scope);
    print_block_row(layer.layer_idx, "V", &metrics_v, warn_count);

    // FFN — uses the FFN-shaped decoder so the rectangular (k × h)
    // payload reconstructs to the right (d × h) tensor.
    let decoded_ffn = decode_ffn_block(&layer.ffn_block, manifest, h);
    let metrics_ffn = compute_metrics(&dense_blocks.ffn, &decoded_ffn, manifest, scope);
    print_block_row(layer.layer_idx, "FFN", &metrics_ffn, warn_count);
}

// ──────────────────────────────────────────────────────────────────────
// main
// ──────────────────────────────────────────────────────────────────────

fn main() -> ExitCode {
    let args = match parse_args() {
        Ok(a) => a,
        Err(e) => {
            eprintln!("verify-rknot: {e}");
            print_usage();
            return ExitCode::from(2);
        }
    };
    let rknot_path = args.rknot.expect("validated above");
    let dense_path = args.dense.expect("validated above");

    eprintln!(
        "verify-rknot: rknot={} dense={} max_layers={:?} scope={:?}",
        rknot_path.display(),
        dense_path.display(),
        args.max_layers,
        args.metric_scope,
    );

    let mut dense_reader = match DenseKnotReader::open(&dense_path) {
        Ok(r) => r,
        Err(e) => {
            eprintln!("verify-rknot: failed to open dense .knot: {e}");
            return ExitCode::from(1);
        }
    };

    let rknot = match read_rknot_from_file(&rknot_path) {
        Ok(r) => r,
        Err(e) => {
            eprintln!("verify-rknot: failed to read .rknot: {e}");
            return ExitCode::from(1);
        }
    };

    eprintln!(
        "verify-rknot: loaded {} rknot layers (model arch={}, hidden_dim={})",
        rknot.layers.len(),
        rknot.arch_meta.arch,
        rknot.arch_meta.hidden_dim,
    );

    let mut warn_count: u32 = 0;
    let mut layers_checked: u32 = 0;
    for layer in &rknot.layers {
        if let Some(m) = args.max_layers {
            if layer.layer_idx >= m {
                break;
            }
        }
        let dense_blocks = match dense_reader.load_layer_blocks(layer.layer_idx) {
            Ok(b) => b,
            Err(e) => {
                eprintln!(
                    "verify-rknot: failed to load dense layer {}: {e}",
                    layer.layer_idx
                );
                return ExitCode::from(1);
            }
        };
        verify_layer(layer, &dense_blocks, &mut warn_count, args.metric_scope);
        layers_checked += 1;
    }

    eprintln!();
    eprintln!("── verify-rknot summary ──");
    eprintln!("layers checked:              {:>10}", layers_checked);
    eprintln!(
        "blocks below energy {:.2}:  {:>10}",
        ENERGY_WARN_THRESHOLD, warn_count
    );

    if warn_count > 0 && !args.allow_energy_warnings {
        ExitCode::from(1)
    } else {
        if warn_count > 0 && args.allow_energy_warnings {
            eprintln!(
                "verify-rknot: {} block(s) below energy {:.2}; exit 0 (--allow-energy-warnings)",
                warn_count, ENERGY_WARN_THRESHOLD
            );
        }
        ExitCode::SUCCESS
    }
}

// ──────────────────────────────────────────────────────────────────────
// Tests — `compute_metrics` against a hand-crafted (dense, decoded) pair.
//
// No live `.knot` / `.rknot` is required. We construct two `DenseTensor`s
// with known values at known standing positions and assert that the
// reported `max_abs_err`, `mean_abs_err`, and `energy_ratio` match the
// closed-form values.
// ──────────────────────────────────────────────────────────────────────

#[cfg(test)]
mod tests {
    use super::*;

    fn dense_with(rows: u32, cols: u32, fill: f32) -> DenseTensor {
        DenseTensor {
            rows,
            cols,
            data: vec![fill; (rows * cols) as usize],
        }
    }

    fn manifest_at(d: u32, indices: &[u32]) -> SpectralManifest {
        SpectralManifest {
            d,
            k: indices.len() as u32,
            standing_indices: indices.to_vec(),
            amplitudes: vec![1.0; indices.len()],
            phase_alignment: vec![1.0; indices.len()],
        }
    }

    /// Hand-crafted pair where every standing-position decode is exactly
    /// equal to the dense value. Errors must be zero, energy ratio = 1.
    #[test]
    fn metrics_perfect_match() {
        let dense = dense_with(8, 8, 0.5);
        let decoded = dense_with(8, 8, 0.5);
        let m = manifest_at(8, &[0, 2, 5, 7]);
        let r = compute_metrics(&dense, &decoded, &m, MetricScope::Standing);
        assert_eq!(r.max_abs_err, 0.0);
        assert_eq!(r.mean_abs_err, 0.0);
        assert!((r.energy_ratio - 1.0).abs() < 1e-6);
    }

    /// Hand-crafted pair with a constant per-position error. The
    /// standing × standing slice has 4 × 4 = 16 entries; every entry's
    /// dense=0.5, decoded=0.25, so error=0.25. Energy ratio = (0.25)² /
    /// (0.5)² = 0.0625 / 0.25 = 0.25 — well below the 0.95 warn line.
    #[test]
    fn metrics_constant_offset() {
        let dense = dense_with(8, 8, 0.5);
        let decoded = dense_with(8, 8, 0.25);
        let m = manifest_at(8, &[0, 2, 5, 7]);
        let r = compute_metrics(&dense, &decoded, &m, MetricScope::Standing);
        assert!((r.max_abs_err - 0.25).abs() < 1e-6);
        assert!((r.mean_abs_err - 0.25).abs() < 1e-6);
        assert!((r.energy_ratio - 0.25).abs() < 1e-6);
        assert!(r.energy_ratio < ENERGY_WARN_THRESHOLD);
    }

    /// A handful of standing positions where one position carries a
    /// large error that should dominate `max_abs_err` but be averaged
    /// out in `mean_abs_err`.
    #[test]
    fn metrics_one_outlier() {
        let mut dense = dense_with(4, 4, 0.0);
        let mut decoded = dense_with(4, 4, 0.0);
        // Standing positions: (0, 0), (0, 2), (2, 0), (2, 2).
        let pairs = [(0u32, 0u32), (0, 2), (2, 0), (2, 2)];
        for &(i, j) in &pairs {
            let idx = (i * 4 + j) as usize;
            dense.data[idx] = 1.0;
            decoded.data[idx] = 1.0;
        }
        // Inject one outlier at (2, 2): decoded drops to 0.0.
        decoded.data[(2 * 4 + 2) as usize] = 0.0;

        let m = manifest_at(4, &[0, 2]);
        let r = compute_metrics(&dense, &decoded, &m, MetricScope::Standing);
        // max_err is the (2, 2) gap = 1.0.
        assert!((r.max_abs_err - 1.0).abs() < 1e-6);
        // mean_err = (0 + 0 + 0 + 1) / 4 = 0.25.
        assert!((r.mean_abs_err - 0.25).abs() < 1e-6);
        // energy_ratio = sum decoded² / sum dense² = 3 / 4 = 0.75.
        assert!((r.energy_ratio - 0.75).abs() < 1e-6);
        assert!(r.energy_ratio < ENERGY_WARN_THRESHOLD);
    }

    /// Energy-zero dense tensor: ratio is vacuously 1.0 (the "no energy
    /// to preserve" base case) so the WARN line doesn't fire on a true
    /// all-zeros block.
    #[test]
    fn metrics_zero_dense_returns_unit_energy() {
        let dense = dense_with(4, 4, 0.0);
        let decoded = dense_with(4, 4, 0.0);
        let m = manifest_at(4, &[0, 1, 2, 3]);
        let r = compute_metrics(&dense, &decoded, &m, MetricScope::Standing);
        assert_eq!(r.energy_ratio, 1.0);
    }

    /// Standing index out of bounds for the tensor must be skipped, not
    /// silently included via `DenseTensor::get`'s zero-clamp. We
    /// construct a 4 × 4 tensor and a manifest that lists index 7 (out
    /// of range): the metric should ignore index 7 entirely and stay
    /// equivalent to a manifest of just `[0, 2]`.
    #[test]
    fn metrics_skip_out_of_range_standing_index() {
        let dense = dense_with(4, 4, 0.5);
        let decoded = dense_with(4, 4, 0.5);
        let m_full = manifest_at(8, &[0, 2, 7]);
        let m_in_range = manifest_at(8, &[0, 2]);
        let r_full = compute_metrics(&dense, &decoded, &m_full, MetricScope::Standing);
        let r_in_range = compute_metrics(&dense, &decoded, &m_in_range, MetricScope::Standing);
        assert_eq!(r_full.max_abs_err, r_in_range.max_abs_err);
        assert_eq!(r_full.mean_abs_err, r_in_range.mean_abs_err);
        assert!((r_full.energy_ratio - r_in_range.energy_ratio).abs() < 1e-6);
    }

    /// Small overshoot in decoded values produces `energy_ratio > 1`,
    /// which is fine — the metric is one-sided "did we lose energy?"
    /// only at the WARN threshold; a slight overshoot from quantization
    /// should not be flagged.
    #[test]
    fn metrics_decoded_overshoot_not_warned() {
        let dense = dense_with(4, 4, 0.5);
        let decoded = dense_with(4, 4, 0.55);
        let m = manifest_at(4, &[0, 2]);
        let r = compute_metrics(&dense, &decoded, &m, MetricScope::Standing);
        // (0.55)² / (0.5)² = 1.21
        assert!((r.energy_ratio - 1.21).abs() < 1e-3);
        assert!(r.energy_ratio >= ENERGY_WARN_THRESHOLD);
    }

    /// Full scope ignores standing indices and computes over the whole overlap.
    #[test]
    fn metrics_full_scope_uses_entire_tensor() {
        let mut dense = dense_with(2, 2, 1.0);
        let mut decoded = dense_with(2, 2, 1.0);
        dense.data[3] = 3.0;
        decoded.data[3] = 2.0;
        let m = manifest_at(2, &[0]); // standing would only look at (0,0)

        let standing = compute_metrics(&dense, &decoded, &m, MetricScope::Standing);
        let full = compute_metrics(&dense, &decoded, &m, MetricScope::Full);

        assert_eq!(standing.max_abs_err, 0.0);
        assert!((full.max_abs_err - 1.0).abs() < 1e-6);
        assert!(full.mean_abs_err > 0.0);
    }
}
